<?php

namespace Src\Containers\Billing\BillSelfAppeal\Actions;

use Src\Ship\Parents\Actions\Action;
use Src\Containers\Biller\BillerSent\Actions\CreateBillerSent;
use Src\Containers\Biller\BillerSent\Models\BillerSent;
use Src\Containers\Billing\BillSelfAppeal\DTO\BillSelfAppealDTO;
use Src\Containers\Billing\BillSelfAppeal\Models\BillSelfAppeal;
use Src\Containers\Billing\BillSelfAppeal\Events\BillSelfAppealUpdated;
use Src\Containers\Billing\Bill\Actions\UpdateBillDocumentsFolderAction;

class UpdateBillSelfAppealAction extends Action
{
    public function __construct(
        private UpdateBillDocumentsFolderAction $updateBillDocumentsFolderAction,
        private CreateBillerSent $createBillerSentAction,
    ) {}

    public function run(BillSelfAppeal $billSelfAppeal, BillSelfAppealDTO $dto)
    {
        $isAppealed = $billSelfAppeal->response_date ? true : false;

        $data = $dto->toArray();
        unset($data['resync_documents']);

        $billSelfAppeal->update($data);

        $documentIds = collect($dto->documents)->pluck('id')->toArray();
        $billSelfAppeal->documents()->sync($documentIds);

        BillSelfAppealUpdated::dispatch($billSelfAppeal);

        if ($dto->resync_documents === true) {
            $this->updateBillDocumentsFolderAction->run($billSelfAppeal->bill, BillSelfAppeal::class);
        }

        $billSelfAppeal->bill->userTouch();

        if (!$isAppealed && $billSelfAppeal->response_date) {
            $this->createBillerSentAction->run($billSelfAppeal->bill, BillerSent::BILL_TYPE_APPEALED);
        }

        return $billSelfAppeal;
    }
}


