use Src\Ship\Parents\Actions\Action;
use Src\Containers\Clinic\Models\Clinic;
use Src\Containers\Billing\BillStatus\Models\BillStatus;
use Src\Containers\Cache\Services\CacheJobDispatcher;

class NotifyBillStatusCacheUpdateAction extends Action
{
    public function __construct(
        private CacheJobDispatcher $cacheJobDispatcher
    ) {}

    public function run(BillStatus $billStatus): void
    {
        $clinicId = $billStatus->clinic_id ?? $billStatus->getAttribute('clinic_id');

        if ($clinicId === null) {
            return;
        }

        $clinic = Clinic::withoutGlobalScopes()->find($clinicId);

        if ($clinic === null) {
            return;
        }

        $billerId = $clinic->owner_id ?? $clinic->id;

        $clinicIds = Clinic::withoutGlobalScopes()
            ->where(function ($query) use ($billerId) {
                $query->where('owner_id', $billerId)
                    ->orWhere('id', $billerId);
            })
            ->whereNull('deleted_at')
            ->pluck('id');

        DB::afterCommit(function () use ($clinicIds) {
            foreach ($clinicIds as $id) {
                $this->cacheJobDispatcher->dispatchJobsForTag(BillStatus::class, $id);
            }
        });
    }
}


