<?php

namespace Src\Containers\Billing\Support;

use InvalidArgumentException;

final class BillStatusDateIntervals
{
    private const COLUMN = 'bill_status_date';

    public static function whereSql(array $interval): string
    {
        return self::buildWhereSql($interval, true);
    }

    public static function caseWhereSql(array $interval): string
    {
        return self::buildWhereSql($interval, true);
    }

    private static function buildWhereSql(array $interval, bool $includeFutureForZeroStart): string
    {
        if (!array_key_exists(0, $interval)) {
            throw new InvalidArgumentException('Bill status date interval must include a start day.');
        }

        $start = self::normalizeDay($interval[0]);

        if (!array_key_exists(1, $interval)) {
            return self::COLUMN . ' <= ' . self::dateSubSql($start);
        }

        $end = self::normalizeDay($interval[1]);

        if ($start === 0 && $includeFutureForZeroStart) {
            return self::COLUMN . ' >= ' . self::dateSubSql($end);
        }

        return self::COLUMN . ' BETWEEN ' . self::dateSubSql($end) . ' AND ' . self::dateSubSql($start);
    }

    public static function apply($query, array $interval)
    {
        return $query->whereRaw(self::whereSql($interval));
    }

    public static function caseExpression(array $intervals): string
    {
        $cases = [];

        foreach ($intervals as $index => $interval) {
            $cases[] = 'WHEN ' . self::caseWhereSql($interval) . ' THEN ' . (int) $index;
        }

        return implode(' ', $cases);
    }

    private static function normalizeDay($day): int
    {
        return max(0, (int) $day);
    }

    private static function dateSubSql(int $days): string
    {
        return "DATE_SUB(CURDATE(), INTERVAL {$days} DAY)";
    }
}

